#include <cstring>
#include <cstdio>
#include <iostream>

void safeFunction(const char* input, size_t inputLen) {
    char buffer[256];
    strncpy(buffer, input, sizeof(buffer) - 1); // Compliant - bounds checking
    buffer[sizeof(buffer) - 1] = '\0';         // Null terminate

    std::string line;
    std::getline(std::cin, line); // Compliant - safe input

    snprintf(buffer, sizeof(buffer), "%s", input); // Compliant - size specified
}

